class Solution { public: int uniqueXorTriplets(vector<int>& nums) { const int MAXX = 2048; vector<bool> pairXor(MAXX, false); vector<bool> ans(MAXX, false); for (int i = 0; i < nums.size(); i++) { for (int j = i; j < nums.size(); j++) { pairXor[nums[i] ^ nums[j]] = true; } } for (int x = 0; x < MAXX; x++) { if (!pairXor[x]) continue; for (int num : nums) { ans[x ^ num] = true; } } int res = 0; for (bool b : ans) res += b; return res; } };